using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using verii_metivon_api.Modules.Counting.Domain.Entities;namespace verii_metivon_api.Modules.Counting.Infrastructure.Persistence.Configurations;public sealed class InventoryCountConfiguration:IEntityTypeConfiguration<InventoryCount>{public void Configure(EntityTypeBuilder<InventoryCount>b){b.ToTable("RII_INVENTORY_COUNTS");b.HasIndex(x=>x.CountNumber).IsUnique();b.Property(x=>x.CountNumber).HasMaxLength(40).IsRequired();}}public sealed class InventoryCountLineConfiguration:IEntityTypeConfiguration<InventoryCountLine>{public void Configure(EntityTypeBuilder<InventoryCountLine>b){b.ToTable("RII_INVENTORY_COUNT_LINES");b.HasIndex(x=>new{x.InventoryCountId,x.LineNumber}).IsUnique();foreach(var p in new[]{nameof(InventoryCountLine.SystemQuantity),nameof(InventoryCountLine.CountedQuantity),nameof(InventoryCountLine.DifferenceQuantity),nameof(InventoryCountLine.UnitCost)})b.Property(p).HasPrecision(24,8);b.HasOne(x=>x.InventoryCount).WithMany(x=>x.Lines).HasForeignKey(x=>x.InventoryCountId).OnDelete(DeleteBehavior.Restrict);}}
public sealed class InventoryCountParameterSettingsConfiguration:IEntityTypeConfiguration<InventoryCountParameterSettings>{public void Configure(EntityTypeBuilder<InventoryCountParameterSettings>b){b.ToTable("RII_INVENTORY_COUNT_PARAMETERS",t=>{t.HasCheckConstraint("CK_RII_INVENTORY_COUNT_PARAMETERS_MAX_LINES","[MaximumLinesPerCount] >= 1 AND [MaximumLinesPerCount] <= 100000");t.HasCheckConstraint("CK_RII_INVENTORY_COUNT_PARAMETERS_TOLERANCE","[AutomaticApprovalQuantityTolerance] >= 0 AND [AutomaticApprovalPercentTolerance] >= 0 AND [AutomaticApprovalPercentTolerance] <= 100");});b.HasKey(x=>x.Id);b.HasQueryFilter(x=>!x.IsDeleted);b.HasIndex(x=>new{x.BranchId,x.WarehouseId}).IsUnique().HasFilter("[IsDeleted] = 0");b.Property(x=>x.AutomaticApprovalQuantityTolerance).HasPrecision(24,8);b.Property(x=>x.AutomaticApprovalPercentTolerance).HasPrecision(9,6);b.Property(x=>x.PostingCurrencyCode).HasMaxLength(3).IsUnicode(false).IsRequired();b.Property(x=>x.RowVersion).IsRowVersion();b.HasOne(x=>x.Branch).WithMany().HasForeignKey(x=>x.BranchId).OnDelete(DeleteBehavior.Restrict);b.HasOne(x=>x.Warehouse).WithMany().HasForeignKey(x=>x.WarehouseId).OnDelete(DeleteBehavior.Restrict);}}
